//! Zalgo (combining-mark-saturated) text corpus shared by the Unicode
//! submodule tests. Each sample buries ASCII base characters under stacks of
//! nonspacing combining marks. Every mark is drawn from U+0300..U+036F filtered
//! to gc=Mn with a nonzero canonical combining class, which guarantees that
//! each one is simultaneously:
//!   * Grapheme_Extend  -> base + marks collapse to a single grapheme (GB9)
//!   * zero-width        -> contributes 0 terminal columns
//!   * a non-starter (ccc != 0) -> only the base characters are starters
//!
//! From those three facts, a sample needs only its `text` and `base_count` to
//! drive every Unicode submodule test:
//!   grapheme clusters     == base_count
//!   terminal columns       == base_count   (ASCII bases are 1 column each)
//!   ccc==0 codepoints      == base_count
//!
//! Adding a new torture case is therefore "just add the input": append a
//! `Sample` with its text and the count of base characters; every submodule
//! test below picks it up automatically.
//!
//! Generated, not hand-typed, so the mark stacks are genuinely random within
//! the constrained pool (see the project test notes). Do not edit the escapes
//! by hand -- regenerate if the corpus needs to change.

const std = @import("std");
const encoding = @import("encoding");
const CodePoint = encoding.CodePoint;

/// Decode a sample's UTF-8 `text` into an owned slice of scalars. Caller frees
/// with the same allocator. The corpus is well-formed, so the lossy decoder
/// never substitutes -- it just spares the tests their own decode boilerplate.
pub fn decode(allocator: std.mem.Allocator, text: []const u8) ![]CodePoint {
    var list: std.ArrayList(CodePoint) = .empty;
    errdefer list.deinit(allocator);
    var it = encoding.utf8.lossyIterator(text);
    while (it.next()) |cp| try list.append(allocator, cp);
    return list.toOwnedSlice(allocator);
}

pub const Sample = struct {
    /// Human-readable tag for failure messages.
    name: []const u8,
    /// The base characters before decoration, e.g. "Zalgo". All ASCII, so the
    /// expected terminal width equals `base_count`.
    base: []const u8,
    /// UTF-8 Zalgo text: the bases with combining marks stacked on each.
    text: []const u8,
    /// Count of base/starter characters. Equals the grapheme-cluster count,
    /// the terminal column width, and the number of ccc==0 scalars.
    base_count: usize,
    /// Total scalar count (bases + marks); a loose upper bound for buffers.
    total_cps: usize,
};

